// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  const now = new Date();
  const tomorrow = new Date(now.getTime() + 24 * 60 * 60 * 1000); // Add 1 day in ms
  item.json.timestamp = tomorrow.toISOString(); // Compatible with Supabase timestampz
}

return $input.all();

const { execSync } = require('child_process');

try {
  execSync('ffmpeg -version');
  return [{ json: { ffmpeg_status: "FFmpeg is installed" } }];
} catch (error) {
  return [{ json: { ffmpeg_status: "FFmpeg is NOT installed" } }];
}

const { execSync, writeFileSync, readFileSync } = require('child_process');
const fs = require('fs');

// Récupère les données binaires du nœud précédent
const binaryData = $input.first().binary.data;
const responseId = $('Generate Audio').item.json.responseId;

// Chemins
const inputFile = `/home/node/.n8n/${responseId}-in.pcm`;
const outputFile = `/home/node/.n8n/${responseId}-out.mp3`;

// 1. Écrire le fichier PCM
const buffer = Buffer.from(binaryData.data, 'base64');
fs.writeFileSync(inputFile, buffer);

// 2. Convertir avec FFmpeg
const command = `ffmpeg -f s16le -ar 24000 -ac 1 -i ${inputFile} -codec:a libmp3lame -qscale:a 2 ${outputFile} -y`;
execSync(command);

// 3. Lire le fichier MP3 résultant
const mp3Buffer = fs.readFileSync(outputFile);
const mp3Base64 = mp3Buffer.toString('base64');

// 4. Nettoyer les fichiers temporaires
fs.unlinkSync(inputFile);
fs.unlinkSync(outputFile);

// 5. Retourner le fichier MP3 en binaire
return [{
  json: { success: true },
  binary: {
    data: {
      data: mp3Base64,
      mimeType: 'audio/mpeg',
      fileName: `${responseId}.mp3`
    }
  }
}];
